def shortestMatchingSubstring(s: str, p: str) -> int:
    m = len(p)
    dp = [0] * (len(s) + 1)
    for i in range(1, len(s) + 1):
        for j in range(m):
            if s[i - 1] == p[j]:
                dp[i] = min(dp[i], dp[i - 1] + 1)
                if j == m - 1:
                    dp[i] = min(dp[i], dp[i - m + 1])
    return dp[len(s)]

